using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
            // Existing 500K documents use "Discriminator". Without this, EF9 can't find them.
            // This also keeps direct SQL queries (WHERE c.Discriminator = ...) working.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id format changed from "Product|123" to just "123" in EF Core 9.
            // Existing documents have the old "Product|123" format.
            // Preserve it so EF9 can read/update existing documents.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<IdValueGenerator>();
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Globally restore the EF8 id format: "EntityType|KeyValue"
        configurationBuilder.Conventions.Add(_ => new IdFormatConvention());
    }
}
