using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF Core 9.
            // Existing 500K documents store "Discriminator"; direct SQL queries reference it.
            // Restore old name so EF9 reads existing docs and raw SQL keeps working.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — id value format changed in EF Core 9.
            // EF8 wrote  id = "Product|123".  EF9 writes id = "123".
            // Existing documents use the old format; point reads will 404 without this.
            entity.Property<string>("__id")
                  .HasValueGenerator<LegacyIdGenerator>();
        });
    }
}

/// <summary>
/// Reproduces the EF Core 8 Cosmos id format: "EntityTypeName|PrimaryKeyValue".
/// </summary>
class LegacyIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var typeName = entry.Metadata.ShortName();
        var pk = entry.Metadata.FindPrimaryKey()!;
        var keyValues = string.Join("|",
            pk.Properties.Select(p => entry.Property(p).CurrentValue));
        return $"{typeName}|{keyValues}";
    }
}

